INSERT INTO ref_institution_agreement
  (institution_id, partner_id, agreement_type, kpi_weight, system_status,
   effective_from, effective_to, notes)
SELECT
  i.id,
  p.id,  -- NULL for DIRECT rows (LEFT JOIN returns NULL when partner_name is NULL)
  na.agreement_type,
  na.kpi_weight,
  na.system_status,
  '2024-01-01'::date,
  '2026-12-31'::date,
  na.agreement_notes
FROM new_agreements na
JOIN ref_institution i ON i.canonical_name = na.canonical_name
LEFT JOIN ref_partner p ON p.name = na.partner_name
WHERE
  -- Skip VIA_PARTNER rows where the partner couldn't be resolved
  -- (this would violate chk_agreement_consistency)
  NOT (na.agreement_type = 'VIA_PARTNER' AND p.id IS NULL)
ON CONFLICT (institution_id, COALESCE(partner_id, 0), effective_from) DO NOTHING;

COMMIT;

