-- Total agreement rows after migration (was 122; expect +~3,127)
SELECT COUNT(*) AS total_agreements FROM ref_institution_agreement;

-- Breakdown by status
SELECT agreement_type, system_status, kpi_weight, COUNT(*) AS rows
FROM ref_institution_agreement
GROUP BY agreement_type, system_status, kpi_weight
ORDER BY agreement_type, system_status, kpi_weight;

